mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM resumes r
    JOIN personal_profiles pp ON pp.id = r.personal_profile_id
    WHERE r.id = #{resumeId}
      AND pp.user_id = #{userId}
      AND r.deleted_at IS NULL
)

SELECT EXISTS (
    SELECT 1
    FROM job_applications
    WHERE user_id = #{userId}
      AND job_post_id = #{jobPostId}
      AND status != 'CANCELED'
)

mapper.insert:
INSERT INTO job_application_attachments ( application_id, file_id ) SELECT #{applicationId}, f.id FROM files f WHERE f.uploader_user_id = #{userId} AND f.file_category = 'ATTACHMENT' AND f.id IN
#{fileId}
ON CONFLICT (application_id, file_id) DO NOTHING

mapper.select:
SELECT
FROM job_applications ja JOIN job_posts jp ON jp.id = ja.job_post_id JOIN company_profiles cp ON cp.id = jp.company_profile_id JOIN users u ON u.id = ja.user_id JOIN personal_profiles pp ON pp.user_id = u.id JOIN resumes r ON r.id = ja.resume_id WHERE cp.user_id = #{userId}
AND ja.job_post_id = #{jobPostId}
ORDER BY ja.applied_at DESC, ja.id DESC
